#' @export
codeguruprofiler <- function(config = list()) {
  paws.developer.tools::codeguruprofiler(config)
}

#' Amazon CodeGuru Reviewer
#'
#' @description
#' This section provides documentation for the Amazon CodeGuru Reviewer API
